SELECT user_id, COUNT(face_id) AS total_faces
FROM faces
GROUP BY user_id;

SELECT COUNT(DISTINCT al.user_id) AS unique_users_count
FROM analysis_logs al
JOIN devices d ON al.device_id = d.device_id;

SELECT user_id, image_path
FROM faces
ORDER BY user_id ASC;

SELECT COUNT(expression_id) AS total_expressions
FROM expressions
WHERE device_id = 5 AND location = 'Office';
